mapper.insert:
insert into job_execution_log (
    file_oper_code, trigger_type, status, summary, error_stack,
    start_time, end_time, create_time
) values (
    #{fileOperCode}, #{triggerType}, #{status}, #{summary}, #{errorStack},
    #{startTime}, #{endTime}, #{createTime}
)

mapper.update:
update job_execution_log
set status = #{status},
    summary = #{summary},
    error_stack = #{errorStack},
    end_time = #{endTime}
where id = #{id}

mapper.select:
select id, file_oper_code, trigger_type, status, summary, error_stack, start_time, end_time, create_time
from job_execution_log
where file_oper_code = #{fileOperCode}
order by id desc
limit #{limit}
